INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00036', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「大約在船後一百米處中鉤的鬼頭刀不斷的翻躍到空中，重重的摔滾在水 面上。已經收回了大約五十米線，牠再度躍出水面。我竟然看到兩隻鬼頭 刀一起跳出水面，幾乎是頭靠著頭一起躍出水面。這是什麼情況？兩隻鬼 頭刀一起躍起，一起摔下，一起游在水裡。這樣的距離已經可以確定，中 鉤的只有一隻，而另一隻是自由的。中鉤的是一隻母魚，而陪她一起摔滾 的是一隻公魚。母魚游向左方，公魚也貼著身游向左邊，那親密的距離彷 彿是在耳邊叮嚀，在耳邊安慰。尤其當我看到那公魚的眼神，不再是記憶 中的倨傲從容，而是無限的悲傷、痛苦或者柔情。」 根據上文，下列選項何者最符合鬼頭刀的情意描寫？', '["兩情若是長久時，又豈在朝朝暮暮", "人老去西風白髮，蝶愁來明日黃花", "問世間情是何物，直教人生死相許", "流光容易把人拋，紅了櫻桃，綠了芭蕉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00037', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「有一種平凡的邪惡，只要我們不再質疑那些令人安心的政治常態，只要 我們不再關心那些事不關己的議題，只要我們漠視他人需求，邪惡的勢力 便會大舉擴張。如此無根無本的邪惡，可以平凡無奇地展現在任何人身上， 一旦人停止思考，浩劫就可能重演。」 根據上文，下列選項何者最符合「平凡的邪惡」的意義？', '["缺乏自覺反思的能力", "缺乏積極向上的心態", "忽略平凡生活的可貴", "缺乏未雨綢繆的遠見"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00038', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「2015年簽訂的《巴黎協議》中，〈第二條〉已明確指出，全球暖化的控 制目標仍將維持在『升溫2℃』以內，並且往1.5℃『努力』。相對積極的 文字條文，也已讓許多專家和公民團體表示肯定。值得注意的是，即使要 達到 1.5℃的控溫目標，意味著所有化石燃料必須很快地被替代。專家們 也指出，協議的許多內容明顯與『1.5℃』的目標相互矛盾，意即其他條文 和重要議題，並沒有朝著1.5℃的方向前進。例如：目前全世界所有的『國 家自主減排貢獻』加總後，連要控溫2℃都有明顯困難，更何況1.5℃？」 根據上文，下列選項何者最符合文意？', '["專家認為《巴黎協議》對防止全球暖化已做出積極有效的控制", "為達到升溫1.5℃的結果，必須儘快改用能替代化石燃料的能源", "《巴黎協議》的條文內容與重要議題均朝向終止全球暖化的結果", "依照「國家自主減排貢獻」的發展現況，應能充分實踐協議目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00039', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「流行歌曲最有趣的是，每一首歌都不能完全描繪你的遭遇，但每一首歌 都可以讓人投射大分量情緒認同。神奇地，在差異中找到一個情緒上的最 大公約數。然而部分社會學者則批評流行音樂，認為流行歌曲將思想與情 感化約成快速可歸類的商品抽屜，阻絕人們往內探究，防止人們深化彼此 差異，因此人們無法發展自我獨特的認知，將人們化約成同一個面目。」 根據上文，下列選項何者正確？', '["流行歌詞善用象徵的表達方式，以小喻大，讓聽眾共鳴", "音樂具有跨語言、跨族群、跨地域的特質，能凝聚聽眾", "流行音樂的大眾商品化，容易讓人忽視個別情感的差異", "強勢商品行銷，使主流音樂衝擊個人創作，弱化多樣性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00040', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「基因體學是近年來最夯的醫學科技，大致分為基因定序、基因檢測及基 因編輯。基因定序是將人體細胞26對染色體DNA遺傳物質排列順序計算 出來；基因檢測是利用已知的基因功能，經過唾液或毛髮比對，了解受測 人是否具有某類遺傳基因，可用於事先了解罹患遺傳性疾病的可能性，也 可做為親子鑑定用途；基因編輯是將具有缺陷的基因片段切除，剪接上具 有正常作用的基因。」 根據上文，下列選項何者最符合文意？', '["基因編輯是將原來的DNA重新排序", "細胞的染色體可自行組合排序與編輯", "基因定序是透過基因功能來做親子鑑定", "基因檢測可以事先了解遺傳性疾病的可能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00041', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「美食外送此一新型職業『技術發展超前，制度卻很落後。』尤其當個人 過度仰賴平臺，而平臺企業的實力又足以壟斷市場時，便能單方面改寫遊 戲規則，造成消費者權益受損、勞動剝削等問題。尤其平臺的運作與升級 是由 AI 等高科技來支持的，更衍生出外送勞動法令與社福制度跟不上科 技變遷的隱憂。」 根據上文，對外送平臺的敘述，何者最適當？', '["就業環境的保障須兼顧技術與制度", "新興科技發展促進了勞動法令修訂", "平臺企業實力越好，外送員的權益也越好", "隨著平臺的擴大，消費者權益也受到保障"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00042', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「記憶是一個建構的過程，或許我們可以把它比作一幅拼貼畫：我們會把 許多碎片湊在一起，然後根據我們的背景知識、渴望和信念把它們都填進 空白處，直到我們完成了一個有用的東西。當我們回想事情時，不是只從 一個舊的檔案櫃裡翻出一張快照；當我們在搜尋時，可能又一邊重組了那 些影像。」 根據上文，下列選項最符合文意的是：', '["記憶就像照相機一樣，能夠完整呈現我們過去的經驗", "記憶經常被修改、變更與重新安排，並不是永恆不變", "記憶可以協助人類將生命中的空白之處填滿，豐富心靈", "記憶如同檔案一樣，貯存在人類大腦深處以供精準調閱"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00043', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「重複、單調及去意義化的工作現場，取代了人與人之間因各式互動接觸 而得以蘊孕發展細微情感的勞動情境。當時間累積得夠久，不論是潛移默 化或有意識地被迫適應，工人都重新建構了思考自身與所處世界的方式。」 根據上文，下列選項最符合文意的是：', '["勞工之間因為高度競爭而不再保持緊密的情感", "工作模式的轉變，影響了勞工彼此的情感聯繫", "勞工價值被簡化成單純的勞動數值而缺乏感情", "面對同事情感淡漠，勞工只能被迫適應來面對"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00044', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「一般人很少想到晶片，但晶片創造了現代世界。國家的命運取決於它們 駕馭運算力的能力。如果沒有半導體與電子產品的貿易，眾所皆知的全球 化不會存在。美國的軍事霸主地位，主要是源自於它把晶片應用在軍事上 的能力。過去半個世紀以來亞洲的驚人崛起，是建立在矽的基礎上，因為 這些不斷成長的經濟體已經把晶片製造及組裝電腦與智慧型手機等產業 加以專業化，這些產業都是靠積體電路撐起來的。」 根據上文，下列選項正確的是：', '["一般人深深意識到現代世界是由晶片所創造的", "國家的命運取決於能否組裝電腦與智慧型手機", "半導體與電子產品對貿易全球化有莫大的影響", "亞洲的驚人崛起是因美國軍事用途晶片需求高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00045', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「許多時候，媒體的問題除了來自過度競爭的商業制度，與惡意的政治操 弄，也和閱聽人的選擇有關。人們很容易偏食地選擇自己相信的媒體，反 而框限了我們的視野。因此，閱聽人也要能反躬自省，自己是否太少思考？ 是否忽略其它的訊息來源與觀點？要能不斷地自我反思與批判，才是能否 成為『耳聰目明』閱聽人的重要關鍵。」 根據上文，下列選項對「閱聽人」的期待何者錯誤？', '["相信權威媒體報導", "養成深度思考能力", "跳脫單一立場解讀", "主動探究資訊來源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
